/**
 * Faza 11.8 — Responsible Gaming & AML Hooks
 *
 * 25 tests covering session limits, min spin time, self-exclusion,
 * AML velocity flagging, win-rate sigma, reality check, and cash-out hold.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { RGSession } from '../src/rg/index.js';

const t0 = 1_000_000;

// ─── RG-01 ────────────────────────────────────────────────────────────────────
describe('RG-01: self_excluded → allow=false', () => {
  it('refuses spin when selfExcluded=true', () => {
    const session = new RGSession({ limits: { selfExcluded: true } });
    const result = session.checkSpinAllowed(1, t0);
    expect(result.allow).toBe(false);
    if (!result.allow) expect(result.reason).toBe('self_excluded');
  });
});

// ─── RG-02 ────────────────────────────────────────────────────────────────────
describe('RG-02: not excluded → allow=true', () => {
  it('allows spin when not self-excluded', () => {
    const session = new RGSession({ limits: { selfExcluded: false } });
    const result = session.checkSpinAllowed(1, t0);
    expect(result.allow).toBe(true);
  });
});

// ─── RG-03 ────────────────────────────────────────────────────────────────────
describe('RG-03: UKGC min spin time not elapsed', () => {
  it('refuses spin when elapsed < 2500ms on UKGC', () => {
    const session = new RGSession({ jurisdiction: 'UKGC' });
    // Record first spin to set lastSpinCompletedAt
    session.recordSpin(1, 0, t0);
    // Try again 1000ms later — still under 2500ms
    const result = session.checkSpinAllowed(1, t0 + 1000);
    expect(result.allow).toBe(false);
    if (!result.allow) expect(result.reason).toBe('min_spin_time_not_elapsed');
  });
});

// ─── RG-04 ────────────────────────────────────────────────────────────────────
describe('RG-04: UKGC, elapsed >= 2500ms → allow=true', () => {
  it('allows spin after 2500ms elapsed on UKGC', () => {
    const session = new RGSession({ jurisdiction: 'UKGC' });
    session.recordSpin(1, 0, t0);
    const result = session.checkSpinAllowed(1, t0 + 2500);
    expect(result.allow).toBe(true);
  });
});

// ─── RG-05 ────────────────────────────────────────────────────────────────────
describe('RG-05: DE, elapsed < 5000ms → refused', () => {
  it('refuses spin when elapsed < 5000ms on DE', () => {
    const session = new RGSession({ jurisdiction: 'DE' });
    session.recordSpin(1, 0, t0);
    const result = session.checkSpinAllowed(1, t0 + 4999);
    expect(result.allow).toBe(false);
    if (!result.allow) expect(result.reason).toBe('min_spin_time_not_elapsed');
  });
});

// ─── RG-06 ────────────────────────────────────────────────────────────────────
describe('RG-06: max_wager exceeded → refused', () => {
  it('refuses spin when wager > maxWagerPerSpin', () => {
    const session = new RGSession({ limits: { maxWagerPerSpin: 10 } });
    const result = session.checkSpinAllowed(11, t0);
    expect(result.allow).toBe(false);
    if (!result.allow) expect(result.reason).toBe('max_wager_exceeded');
  });
});

// ─── RG-07 ────────────────────────────────────────────────────────────────────
describe('RG-07: session loss >= limit → refused', () => {
  it('refuses spin when netLoss >= maxLossPerSession', () => {
    const session = new RGSession({ limits: { maxLossPerSession: 100 } });
    session.recordSpin(100, 0, t0);
    const result = session.checkSpinAllowed(1, t0 + 1);
    expect(result.allow).toBe(false);
    if (!result.allow) expect(result.reason).toBe('max_loss_session');
  });
});

// ─── RG-08 ────────────────────────────────────────────────────────────────────
describe('RG-08: session loss < limit → allowed', () => {
  it('allows spin when netLoss < maxLossPerSession', () => {
    const session = new RGSession({ limits: { maxLossPerSession: 100 } });
    session.recordSpin(50, 0, t0);
    // netLoss = 50 < 100
    const result = session.checkSpinAllowed(1, t0 + 1);
    // 50 < 80 so no loss warning blocks; we need to confirm allow
    expect(result.allow).toBe(true);
  });
});

// ─── RG-09 ────────────────────────────────────────────────────────────────────
describe('RG-09: session duration exceeded → refused', () => {
  it('refuses spin when session duration exceeded', () => {
    const session = new RGSession({ limits: { maxSessionDurationMs: 60_000 } });
    // Try to spin 61 seconds into the session
    const result = session.checkSpinAllowed(1, session.getState().startTime + 60_001);
    expect(result.allow).toBe(false);
    if (!result.allow) expect(result.reason).toBe('max_session_duration');
  });
});

// ─── RG-10 ────────────────────────────────────────────────────────────────────
describe('RG-10: first spin never refused for min_spin_time', () => {
  it('allows very first spin regardless of jurisdiction', () => {
    const session = new RGSession({ jurisdiction: 'UKGC' });
    // No prior spin recorded → lastSpinCompletedAt=0
    const result = session.checkSpinAllowed(1, t0);
    expect(result.allow).toBe(true);
  });
});

// ─── RG-11 ────────────────────────────────────────────────────────────────────
describe('RG-11: recordSpin updates counters correctly', () => {
  it('increments totalWagered, totalWon, netLoss, spinCount', () => {
    const session = new RGSession();
    session.recordSpin(10, 3, t0);
    const state = session.getState();
    expect(state.totalWagered).toBe(10);
    expect(state.totalWon).toBe(3);
    expect(state.netLoss).toBe(7);
    expect(state.spinCount).toBe(1);
  });
});

// ─── RG-12 ────────────────────────────────────────────────────────────────────
describe('RG-12: recordSpin returns empty events when nothing triggered', () => {
  it('returns empty array when no events triggered', () => {
    const session = new RGSession();
    const events = session.recordSpin(1, 0, t0);
    expect(events).toHaveLength(0);
  });
});

// ─── RG-13 ────────────────────────────────────────────────────────────────────
describe('RG-13: reality check fires when interval elapsed', () => {
  it('emits reality_check_due when interval has elapsed', () => {
    const session = new RGSession({ limits: { realityCheckIntervalMs: 30_000 } });
    // First spin at t0
    session.recordSpin(1, 0, t0);
    // Second spin at t0 + 30000 — should fire
    const events = session.recordSpin(1, 0, t0 + 30_000);
    const rcEvent = events.find((e) => e.kind === 'reality_check_due');
    expect(rcEvent).toBeDefined();
  });
});

// ─── RG-14 ────────────────────────────────────────────────────────────────────
describe('RG-14: reality check does not double-fire within interval', () => {
  it('does not re-emit reality_check_due before interval expires again', () => {
    const session = new RGSession({ limits: { realityCheckIntervalMs: 30_000 } });
    session.recordSpin(1, 0, t0);
    // Fire once at t0 + 30000
    session.recordSpin(1, 0, t0 + 30_000);
    // Try again 1ms later — should not fire again
    const events = session.recordSpin(1, 0, t0 + 30_001);
    const rcEvent = events.find((e) => e.kind === 'reality_check_due');
    expect(rcEvent).toBeUndefined();
  });
});

// ─── RG-15 ────────────────────────────────────────────────────────────────────
describe('RG-15: session limit warning at 80%', () => {
  it('emits session_limit_warning when netLoss reaches 80% of limit', () => {
    const session = new RGSession({ limits: { maxLossPerSession: 100 } });
    // Wager 80, win 0 → netLoss = 80 = 80% of 100
    const events = session.recordSpin(80, 0, t0);
    const warnEvent = events.find((e) => e.kind === 'session_limit_warning');
    expect(warnEvent).toBeDefined();
  });
});

// ─── RG-16 ────────────────────────────────────────────────────────────────────
describe('RG-16: AML velocity flag fires when spins/min exceeded', () => {
  it('emits aml_velocity_flag when spins exceed maxSpinsPerMinute', () => {
    const session = new RGSession({ aml: { maxSpinsPerMinute: 5 } });
    let lastEvents: ReturnType<typeof session.recordSpin> = [];
    // Record 6 spins within same second → > 5 per minute
    for (let i = 0; i <= 5; i++) {
      lastEvents = session.recordSpin(1, 0, t0 + i * 10);
    }
    const allEvents = session.getEventLog();
    expect(allEvents.some((e) => e.kind === 'aml_velocity_flag')).toBe(true);
  });
});

// ─── RG-17 ────────────────────────────────────────────────────────────────────
describe('RG-17: AML velocity de-bounce', () => {
  it('does not fire aml_velocity_flag more than once', () => {
    const session = new RGSession({ aml: { maxSpinsPerMinute: 2 } });
    // Trigger 5 spins quickly
    for (let i = 0; i < 5; i++) {
      session.recordSpin(1, 0, t0 + i * 10);
    }
    const velocityFlags = session.getEventLog().filter((e) => e.kind === 'aml_velocity_flag');
    expect(velocityFlags.length).toBe(1);
  });
});

// ─── RG-18 ────────────────────────────────────────────────────────────────────
describe('RG-18: AML win-rate sigma flag after 30+ all-win spins', () => {
  it('emits aml_velocity_flag for win-rate sigma after 30+ consecutive wins', () => {
    // All-win scenario: win rate = 1.0, expected = 0.35 → huge sigma
    const session = new RGSession({ aml: { winRateSigmaThreshold: 2.0 } });
    for (let i = 0; i < 35; i++) {
      session.recordSpin(1, 5, t0 + i * 5_000); // all wins, 5s apart
    }
    const allEvents = session.getEventLog();
    const sigmaFlags = allEvents.filter(
      (e) => e.kind === 'aml_velocity_flag' && typeof e.detail['sigma'] === 'number',
    );
    expect(sigmaFlags.length).toBeGreaterThanOrEqual(1);
  });
});

// ─── RG-19 ────────────────────────────────────────────────────────────────────
describe('RG-19: cashOutHold required above threshold', () => {
  it('returns required=true when amount >= cashOutHoldThreshold', () => {
    const session = new RGSession({ aml: { cashOutHoldThreshold: 500 } });
    const result = session.cashOutHoldRequired(500);
    expect(result.required).toBe(true);
  });
});

// ─── RG-20 ────────────────────────────────────────────────────────────────────
describe('RG-20: cashOutHold false below threshold', () => {
  it('returns required=false when amount < cashOutHoldThreshold', () => {
    const session = new RGSession({ aml: { cashOutHoldThreshold: 500 } });
    const result = session.cashOutHoldRequired(499);
    expect(result.required).toBe(false);
  });
});

// ─── RG-21 ────────────────────────────────────────────────────────────────────
describe('RG-21: getState returns snapshot', () => {
  it('getState returns immutable snapshot of session state', () => {
    const session = new RGSession({ jurisdiction: 'IT', limits: { maxLossPerSession: 200 } });
    session.recordSpin(30, 10, t0);
    const state = session.getState();
    expect(state.jurisdiction).toBe('IT');
    expect(state.totalWagered).toBe(30);
    expect(state.totalWon).toBe(10);
    expect(state.netLoss).toBe(20);
    expect(state.spinCount).toBe(1);
    expect(state.limits.maxLossPerSession).toBe(200);
  });
});

// ─── RG-22 ────────────────────────────────────────────────────────────────────
describe('RG-22: getEventLog returns all events', () => {
  it('getEventLog contains all emitted events in order', () => {
    const session = new RGSession({
      limits: { realityCheckIntervalMs: 5_000, maxLossPerSession: 100 },
    });
    session.recordSpin(80, 0, t0);           // triggers warning
    session.recordSpin(1, 0, t0 + 5_000);   // triggers reality check
    const log = session.getEventLog();
    expect(log.length).toBeGreaterThanOrEqual(2);
    expect(log.some((e) => e.kind === 'session_limit_warning')).toBe(true);
    expect(log.some((e) => e.kind === 'reality_check_due')).toBe(true);
  });
});

// ─── RG-23 ────────────────────────────────────────────────────────────────────
describe('RG-23: 10 spins accumulate correctly', () => {
  it('accumulates totals over 10 spins', () => {
    const session = new RGSession();
    for (let i = 0; i < 10; i++) {
      session.recordSpin(5, 2, t0 + i * 1_000);
    }
    const state = session.getState();
    expect(state.totalWagered).toBe(50);
    expect(state.totalWon).toBe(20);
    expect(state.netLoss).toBe(30);
    expect(state.spinCount).toBe(10);
  });
});

// ─── RG-24 ────────────────────────────────────────────────────────────────────
describe('RG-24: default jurisdiction has 0 min spin time', () => {
  it('never refuses for min spin time on default jurisdiction', () => {
    const session = new RGSession({ jurisdiction: 'default' });
    session.recordSpin(1, 0, t0);
    // Immediately try again — 0ms elapsed
    const result = session.checkSpinAllowed(1, t0);
    expect(result.allow).toBe(true);
  });
});

// ─── RG-25 ────────────────────────────────────────────────────────────────────
describe('RG-25: getAMLState returns AML state', () => {
  it('getAMLState reflects recorded spins and wins', () => {
    const session = new RGSession({ aml: { maxSpinsPerMinute: 100 } });
    session.recordSpin(5, 10, t0);
    session.recordSpin(5, 0, t0 + 1_000);
    const aml = session.getAMLState();
    expect(aml.totalSpins).toBe(2);
    expect(aml.totalWins).toBe(1);
    expect(aml.flagged).toBe(false);
  });
});

tests/w239_analyzer_extra_killers.test.t.source:
/**
 * W239 — extra Stryker mutation killers for `src/sensitivity/analyzer.ts`.
 *
 * Targets the 27 surviving mutants in the 2026-05-13 scoped report,
 * complementing `tests/faza67_sensitivity_mutation_strengthening.test.ts`
 * and `tests/faza67_sensitivity_strength.test.ts`.
 *
 * Mutant groups addressed here:
 *   * L26:7, L34:9, L206:7, L95:25, L220:45 ConditionalExpression false
 *   * L31:19 EqualityOperator `< vs <=` on reel loop
 *   * L68/L133/L215/L216/L217 LogicalOperator on `??` default fallbacks
 *   * L70:22 ArithmeticOperator `1 + delta` vs `1 - delta`
 *   * L79:41, L220:38 ArrowFunction return undefined
 *   * L91/L241 ObjectLiteral `{}` returns
 *   * L93/L94 ArithmeticOperator (perturbed - base) shape
 *   * L95:39 ArithmeticOperator `rtpDelta / delta` direction
 *   * L108:26 MethodExpression — slice() returns a copy not original
 *   * L170:28 ArithmeticOperator on `achievedRtp - target`
 *   * L171:9 / L177:9 EqualityOperator boundary on error vs tolerance
 *   * L177:41 BlockStatement bracket-update side-effect
 *   * L206:37 BlockStatement non-weighted early-return
 *   * L220:56 StringLiteral '' fallback id
 *
 * Imports use the .js extension required by tsconfig ESM mode.
 */

import { describe, it, expect } from 'vitest';
import {
  applyWeightMultiplier,
  analyzeSensitivity,
  solveTargetRtp,
  autoTune,
} from '../src/sensitivity/analyzer.js';
import type { SlotGameIR } from '../src/ir/types.js';

// ── Minimal weighted IR fixture (deterministic, lightweight) ────────────

function weightedIr(): SlotGameIR {
  return {
    schemaVersion: '1.0',
    meta: { id: 'W239', name: 'w239-test', version: '1', themeTags: [] },
    topology: { kind: 'rectangular', reels: 3, rows: 3 },
    symbols: [
      { id: 'S_A', name: 'A', kind: 'hp' },
      { id: 'S_B', name: 'B', kind: 'lp' },
      { id: 'S_W', name: 'W', kind: 'wild' },
    ],
    reels: {
      mode: 'weighted',
      base: [
        { S_A: 10, S_B: 20, S_W: 5 },
        { S_A: 10, S_B: 20, S_W: 5 },
        { S_A: 10, S_B: 20, S_W: 5 },
      ],
    },
    evaluation: {
      kind: 'lines',
      direction: 'ltr',
      minMatch: 3,
      payLeftToRightOnly: true,
      paylines: [
        [1, 1, 1],
        [0, 0, 0],
        [2, 2, 2],
      ],
    },
    paytable: {
      S_A: { '3': 10 },
      S_B: { '3': 5 },
      S_W: { '3': 50 },
    },
    features: [],
    rng: { kind: 'mulberry32', defaultSeed: 42 },
    bet: { currency: 'USD', baseBet: 1, denominations: [1] },
    limits: {
      targetRtp: 0.96,
      rtpTolerance: 0.01,
      maxWinX: 5000,
      winCapApply: 'per_spin',
      targetVolatility: 'medium',
      hitFreqTarget: 0.25,
    },
    compliance: {
      jurisdictions: ['XX'],
      rtpRangeRequired: [0.85, 0.99],
      maxWinCapRequired: 5000,
      nearMissRule: 'must_be_random',
      ldwDisclosure: false,
      sessionTimeDisplay: false,
    },
    rtpAllocation: {
      baseGame: 80,
      freeSpins: 15,
      holdAndWin: 5,
      jackpot: 0,
      tolerance: 1,
    },
  } as SlotGameIR;
}

function stripsIr(): SlotGameIR {
  const ir = weightedIr();
  ir.reels = {
    mode: 'strips',
    base: [
      ['S_A', 'S_B', 'S_W'],
      ['S_A', 'S_B', 'S_W'],
      ['S_A', 'S_B', 'S_W'],
    ],
  };
  return ir;
}

// ── L26:7 ConditionalExpression — non-weighted early-return in applyWeightMultiplier

describe('W239 — applyWeightMultiplier non-weighted early return (L26)', () => {
  it('strips IR: returns clone with mode=strips, no mutation applied', () => {
    const ir = stripsIr();
    const out = applyWeightMultiplier(ir, 'S_A', [0, 1, 2], 5);
    expect(out.reels.mode).toBe('strips');
    // Same structural shape — the early return must produce a deep clone.
    expect(out).not.toBe(ir);
    expect(out.reels).toEqual(ir.reels);
  });
});

// ── L31:19 EqualityOperator — reel loop bound `< vs <=` ──────────────────

describe('W239 — applyWeightMultiplier reel-loop bound (L31)', () => {
  it('mutating ALL reel indices touches every reel (len-1 must be included)', () => {
    const ir = weightedIr();
    const out = applyWeightMultiplier(ir, 'S_A', [0, 1, 2], 3);
    // Original `< length` mutates indices 0,1,2.
    // Mutant `<= length` would also try index 3, which doesn't exist and
    // crashes; we cover that path via correct-bound assertion below.
    const reels = out.reels as Extract<typeof out.reels, { mode: 'weighted' }>;
    expect(reels.base.length).toBe(3);
    expect(reels.base[0]?.S_A).toBe(30);
    expect(reels.base[1]?.S_A).toBe(30);
    expect(reels.base[2]?.S_A).toBe(30);
  });
});

// ── L34:9 ConditionalExpression — reelMap missing guard ─────────────────

describe('W239 — applyWeightMultiplier missing-reelMap guard (L34)', () => {
  it('reelSet entry that resolves to no map is skipped silently', () => {
    const ir = weightedIr();
    // Inject a sparse hole at index 1 by clearing its map reference.
    const reels = ir.reels as Extract<typeof ir.reels, { mode: 'weighted' }>;
    // @ts-expect-error — test fixture intentionally violates the type.
    reels.base[1] = undefined;
    const out = applyWeightMultiplier(ir, 'S_A', [0, 1, 2], 2);
    const outReels = out.reels as Extract<typeof out.reels, { mode: 'weighted' }>;
    expect(outReels.base[0]?.S_A).toBe(20);
    // Index 1 was undefined → guard must skip it without throwing.
    expect(outReels.base[2]?.S_A).toBe(20);
  });
});

// ── L70:22 ArithmeticOperator — `1 + delta` direction ───────────────────

describe('W239 — analyzeSensitivity multiplier direction (L70)', () => {
  it('multiplier = 1 + delta (not 1 - delta): perturbed weights grow', async () => {
    const ir = weightedIr();
    // With delta=0.5: multiplier should be 1.5 (perturbing UP).
    // To verify direction without running MC twice, we exercise the
    // function and confirm sensitivity sign aligns with rtpDelta sign.
    const report = await analyzeSensitivity(ir, { evalSpins: 2000, delta: 0.5 });
    // sensitivity = rtpDelta / delta — with delta > 0, sign(sensitivity) == sign(rtpDelta).
    for (const d of report.deltas) {
      if (d.rtpDelta !== 0) {
        expect(Math.sign(d.sensitivity)).toBe(Math.sign(d.rtpDelta));
      }
    }
  });
});

// ── L68/L133/L215/L216/L217 LogicalOperator — `??` default fallbacks ────

describe('W239 — analyzeSensitivity default opts (L68)', () => {
  it('omitted opts → evalSpins defaults to 10000 and runs successfully', async () => {
    const ir = weightedIr();
    const report = await analyzeSensitivity(ir);
    expect(Number.isFinite(report.baseRtp)).toBe(true);
    expect(Number.isFinite(report.baseHitRate)).toBe(true);
    expect(report.deltas.length).toBeGreaterThanOrEqual(1);
  });
});

describe('W239 — solveTargetRtp default opts (L133)', () => {
  it('omitted maxIterations → defaults to 50 (assert iterations ≤ 50)', async () => {
    const ir = weightedIr();
    const r = await solveTargetRtp(ir, { targetRtp: 0.99, varySymbol: 'S_A', evalSpins: 200 });
    expect(r.iterations).toBeLessThanOrEqual(50);
    expect(r.iterations).toBeGreaterThan(0);
  });
});

describe('W239 — autoTune default opts (L215-L217)', () => {
  it('omitted maxIterations → defaults to 20', async () => {
    const ir = weightedIr();
    const r = await autoTune(ir, { targetRtp: 0.99, evalSpins: 200 });
    expect(r.iterations).toBeLessThanOrEqual(20);
  });

  it('omitted evalSpins → defaults to 10000 (returned IR is structurally valid)', async () => {
    const ir = weightedIr();
    const r = await autoTune(ir, { targetRtp: 0.95 });
    expect(r.solvedIr.reels.mode).toBe('weighted');
  });
});

// ── L79:41 / L220:38 ArrowFunction — `(_,i) => i` returns the index ─────

describe('W239 — analyzeSensitivity reel-index map returns numeric index (L79)', () => {
  it('all-reel indices traverse 0..N-1 — sensitivity ran across every reel', async () => {
    const ir = weightedIr();
    const report = await analyzeSensitivity(ir, { evalSpins: 500, delta: 0.1 });
    // If the arrow `(_,i) => i` had been replaced with `() => undefined`,
    // allReelIndices would be [undefined, undefined, undefined], the
    // applyWeightMultiplier guard would skip every reel and rtpDelta
    // would be exactly 0 for every symbol.  Any non-zero delta proves
    // the index-returning arrow ran correctly.
    const anyNonZero = report.deltas.some((d) => d.rtpDelta !== 0);
    expect(anyNonZero).toBe(true);
  });
});

// ── L91:64 / L241:68 ObjectLiteral — non-weighted return shape ──────────

describe('W239 — non-weighted early return shapes (L91/L241)', () => {
  it('analyzeSensitivity on strips IR returns the documented zero shape', async () => {
    const ir = stripsIr();
    const r = await analyzeSensitivity(ir);
    expect(r.baseRtp).toBe(0);
    expect(r.baseHitRate).toBe(0);
    expect(r.deltas).toEqual([]);
    expect(r.topInfluencers).toEqual([]);
  });

  it('autoTune on strips IR returns documented zero shape (L241 ObjectLiteral)', async () => {
    const ir = stripsIr();
    const r = await autoTune(ir, { targetRtp: 0.96 });
    expect(r.converged).toBe(false);
    expect(r.achievedRtp).toBe(0);
    expect(r.iterations).toBe(0);
    expect(r.solvedIr).toBe(ir);
  });
});

// ── L93/L94/L95:39 ArithmeticOperator — delta = perturbed − base ────────

describe('W239 — analyzeSensitivity delta arithmetic shape (L93-95)', () => {
  it('|rtpDelta| is small (subtraction, not addition)', async () => {
    const ir = weightedIr();
    const report = await analyzeSensitivity(ir, { evalSpins: 500, delta: 0.05 });
    // Base RTP is < 2 in this fixture; perturbed RTP is also < 2.
    // Correct |perturbed - base| should be < 2.  Mutant perturbed + base
    // would be > 0 plus the perturbation, so > base ≥ 0.
    for (const d of report.deltas) {
      expect(Math.abs(d.rtpDelta)).toBeLessThan(2);
    }
  });

  it('sensitivity = rtpDelta / delta (kills * mutant)', async () => {
    const ir = weightedIr();
    const delta = 0.5;
    const report = await analyzeSensitivity(ir, { evalSpins: 500, delta });
    for (const d of report.deltas) {
      if (d.rtpDelta !== 0) {
        const expectedSens = d.rtpDelta / delta;
        expect(d.sensitivity).toBeCloseTo(expectedSens, 9);
      }
    }
  });
});

// ── L95:25 ConditionalExpression — delta=0 guard ────────────────────────

describe('W239 — analyzeSensitivity delta=0 guard (L95)', () => {
  it('delta=0 produces sensitivity=0, no NaN', async () => {
    const ir = weightedIr();
    const report = await analyzeSensitivity(ir, { evalSpins: 200, delta: 0 });
    for (const d of report.deltas) {
      expect(Number.isNaN(d.sensitivity)).toBe(false);
      expect(d.sensitivity).toBe(0);
    }
  });
});

// ── L108:26 MethodExpression — `slice()` returns a copy ────────────────

describe('W239 — analyzeSensitivity topInfluencers sort isolation (L108)', () => {
  it('deltas array preserves Set insertion order (kills `.slice()` removal mutant)', async () => {
    const ir = weightedIr();
    // Fixture insertion order: S_A, S_B, S_W (Object.keys() iter order on
    // string-keyed objects).  Because Set preserves insertion order and
    // the analyzer iterates `Object.keys(reelMap)` then `symbolIds.add(k)`,
    // deltas[i].symbolId must follow that order exactly.
    const report = await analyzeSensitivity(ir, { evalSpins: 200, delta: 0.1 });
    expect(report.deltas.map((d) => d.symbolId)).toEqual(['S_A', 'S_B', 'S_W']);
    // If `.slice()` were removed (or replaced with `deltas`), `.sort()` on
    // line 110 would mutate the underlying `deltas` array, breaking the
    // insertion-order invariant above.
  });
});

// ── L170:28 / L171:9 / L177:9 — bisection arithmetic / equality ─────────

describe('W239 — solveTargetRtp error arithmetic & convergence boundary (L170-177)', () => {
  it('error is computed as |achievedRtp - target| (kills + mutant)', async () => {
    const ir = weightedIr();
    const r = await solveTargetRtp(ir, {
      targetRtp: 0.96,
      varySymbol: 'S_A',
      evalSpins: 300,
      maxIterations: 5,
    });
    const expected = Math.abs(r.achievedRtp - 0.96);
    expect(r.error).toBeCloseTo(expected, 9);
  });

  it('convergence requires error < tolerance, not <= (strict equality kill)', async () => {
    const ir = weightedIr();
    // With high tolerance, must converge.
    const r = await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'S_A',
      evalSpins: 300,
      maxIterations: 30,
      tolerance: 10, // huge tolerance
    });
    expect(r.converged).toBe(true);
    expect(r.error).toBeLessThan(10);
  });
});

// ── L177:41 BlockStatement — bracket-update side-effect ────────────────

describe('W239 — solveTargetRtp bracket-update keeps direction (L177)', () => {
  it('when achievedRtp > target, hi bound shrinks (binary-search direction)', async () => {
    const ir = weightedIr();
    // Target near 0 forces achievedRtp > target on every iter → hi shrinks
    // → weightChange ends up small (close to lo=0.1).
    const r = await solveTargetRtp(ir, {
      targetRtp: 0.001,
      varySymbol: 'S_A',
      evalSpins: 200,
      maxIterations: 10,
    });
    // After 10 iters of hi shrinking, weightChange should be close to lo (0.1).
    expect(r.weightChange).toBeLessThan(5);
  });
});

// ── L206:7 / L206:37 ConditionalExpression / BlockStatement — autoTune non-weighted

describe('W239 — autoTune non-weighted branch fully exercised (L206)', () => {
  it('strips IR triggers the early-return block without invoking solveTargetRtp', async () => {
    const ir = stripsIr();
    const r = await autoTune(ir, { targetRtp: 0.96 });
    // Early-return must not run any iterations.
    expect(r.iterations).toBe(0);
    expect(r.solvedIr).toBe(ir);
  });
});

// ── L220 ArrowFunction / ConditionalExpression / StringLiteral — wild lookup

describe('W239 — autoTune wild lookup & fallback id (L220)', () => {
  it('finds wild symbol and uses its id as varySymbol', async () => {
    const ir = weightedIr();
    const r = await autoTune(ir, { targetRtp: 0.95, evalSpins: 200, maxIterations: 5 });
    // converged or not, the result must be structurally valid.
    expect(r.solvedIr.reels.mode).toBe('weighted');
    expect(r.iterations).toBeGreaterThan(0);
  });

  it('no wild and no symbols → empty varySymbol → early-return with iterations=0', async () => {
    const ir = weightedIr();
    ir.symbols = [];
    const r = await autoTune(ir, { targetRtp: 0.95, evalSpins: 200 });
    // Empty string fallback (line 221) means varySymbol === '' → early return.
    expect(r.iterations).toBe(0);
    expect(r.converged).toBe(false);
  });

  it('no wild but has other symbols → falls back to first symbol id', async () => {
    const ir = weightedIr();
    ir.symbols = [
      { id: 'S_X', name: 'X', kind: 'hp' },
      { id: 'S_Y', name: 'Y', kind: 'lp' },
    ];
    // S_X is NOT a key in any reelMap, so applyWeightMultiplier won't touch
    // anything, but the function must still complete without error and
    // run at least one iteration.
    const r = await autoTune(ir, { targetRtp: 0.5, evalSpins: 200, maxIterations: 3 });
    expect(r.iterations).toBeGreaterThan(0);
  });
});

tests/faza67_sensitivity_mutation_streng.source:
/**
 * Faza 6.7 + W152 Wave 26 — Stryker mutation strengthening for
 * `src/sensitivity/analyzer.ts`.
 *
 * Baseline (W152 Wave 17, `reports/mutation/scoped-2026-05-13.json`):
 *   * 99 / 128 mutants killed (78.91 %)
 *   * 27 survived — distribution:
 *     ConditionalExpression 6 · LogicalOperator 5 · ArithmeticOperator 5
 *     EqualityOperator 3 · ObjectLiteral 2 · ArrowFunction 2
 *     BlockStatement 2 · MethodExpression 1 · StringLiteral 1
 *
 * Each test below is annotated with the LINE in `analyzer.ts` and the
 * mutant kind it is intended to kill. The annotation is informational
 * — Stryker re-runs to confirm. Test BODIES exercise boundary inputs
 * and assert specific output shape so that swapping operators (`+` for
 * `-`, `&&` for `||`, `<` for `<=`, etc.) makes one of the assertions
 * fail.
 *
 * Run via existing vitest harness:
 *   npm test -- tests/faza67_sensitivity_mutation_strengthening.test.ts
 *
 * Re-measure mutation score:
 *   npx stryker run
 *   npm run mutation-summary
 */

import { describe, it, expect, vi } from 'vitest';

import {
  applyWeightMultiplier,
  analyzeSensitivity,
  solveTargetRtp,
} from '../src/sensitivity/analyzer.js';
import type { SlotGameIR } from '../src/ir/types.js';

vi.setConfig({ testTimeout: 60_000 });

// ─── Minimal weighted IR fixture (kept local so the mutation file is
//     reviewable without cross-file context).
function makeWeightedIR(): SlotGameIR {
  return {
    schema_version: '1.0.0',
    meta: { id: 'sens-mut', name: 'Sensitivity Mut', version: '1.0.0', theme_tags: [] },
    topology: { kind: 'rectangular', reels: 3, rows: 3 },
    symbols: [
      { id: 'LP1', name: 'LP1', kind: 'lp' },
      { id: 'HP1', name: 'HP1', kind: 'hp' },
      { id: 'WLD', name: 'Wild', kind: 'wild', substitutes: '*' },
    ],
    reels: {
      mode: 'weighted',
      base: [
        { LP1: 10, HP1: 3, WLD: 1 },
        { LP1: 10, HP1: 3, WLD: 1 },
        { LP1: 10, HP1: 3, WLD: 1 },
      ],
    },
    evaluation: {
      kind: 'lines',
      paylines: [[1, 1, 1], [0, 0, 0], [2, 2, 2]],
      direction: 'ltr',
      min_match: 3,
      pay_left_to_right_only: true,
    },
    paytable: { LP1: { '3': 0.5 }, HP1: { '3': 3 } },
    features: [],
    rng: { kind: 'mulberry32', default_seed: 42 },
    bet: { currency: 'EUR', base_bet: 1, denominations: [1] },
    limits: {
      target_rtp: 0.95,
      rtp_tolerance: 0.01,
      max_win_x: 1000,
      win_cap_apply: 'per_spin',
      target_volatility: 'medium',
      hit_freq_target: 0.3,
    },
    compliance: {
      jurisdictions: ['MGA'],
      rtp_range_required: [0.92, 0.99],
      max_win_cap_required: 1000,
      near_miss_rule: 'must_be_random',
      ldw_disclosure: true,
      session_time_display: true,
    },
    rtp_allocation: {
      base_game: 1.0,
      free_spins: 0,
      hold_and_win: 0,
      jackpot: 0,
      tolerance: 0.01,
    },
  };
}

// ─── applyWeightMultiplier — boundary mutants ──────────────────────────────

describe('MUT-AWM-01: applyWeightMultiplier — non-weighted IR returns same shape (line 26 ConditionalExpression)', () => {
  it('strips mode → returns unchanged structure', () => {
    const ir: SlotGameIR = {
      ...makeWeightedIR(),
      reels: { mode: 'strips', base: [['LP1'], ['HP1'], ['WLD']] },
    };
    const out = applyWeightMultiplier(ir, 'LP1', [0], 2.0);
    // If the `if (clone.reels.mode !== 'weighted') return clone;` flips to
    // `false`, the function would press on and crash on missing reels.base.
    // Asserting the same `mode` value forces the early-return path to fire.
    expect(out.reels.mode).toBe('strips');
    // Strips path: nothing should have been touched.
    expect((out.reels as { mode: 'strips'; base: string[][] }).base).toEqual([
      ['LP1'],
      ['HP1'],
      ['WLD'],
    ]);
  });
});

describe('MUT-AWM-02: applyWeightMultiplier — reel-index loop boundary (line 31 EqualityOperator: < vs <=)', () => {
  it('out-of-range index does NOT touch reel.length position', () => {
    const ir = makeWeightedIR();
    // reels.base.length === 3; index 3 is one past the end.
    const out = applyWeightMultiplier(ir, 'LP1', [3], 5.0);
    const weighted = out.reels as Extract<typeof out.reels, { mode: 'weighted' }>;
    // No reel got mutated — every reel still has LP1=10.
    for (const reel of weighted.base) {
      expect(reel['LP1']).toBe(10);
    }
    // If the loop bound were `i <= reels.base.length` (Stryker mutant), the
    // loop would attempt `reels.base[3]` which is undefined and would
    // either crash or silently no-op. Our assertion is the same either way
    // but the mutation also bumps `i` past the valid set causing the
    // `if (!reelSet.has(i))` branch to flip identity coverage.
  });
});

describe('MUT-AWM-03: applyWeightMultiplier — reelSet.has guard prevents wrong-reel mutation (line 34 ConditionalExpression)', () => {
  it('mutating reel 1 leaves reel 0 and reel 2 unchanged', () => {
    const ir = makeWeightedIR();
    const out = applyWeightMultiplier(ir, 'LP1', [1], 2.0);
    const weighted = out.reels as Extract<typeof out.reels, { mode: 'weighted' }>;
    expect(weighted.base[0]!['LP1']).toBe(10);
    expect(weighted.base[1]!['LP1']).toBe(20);
    expect(weighted.base[2]!['LP1']).toBe(10);
  });
});

describe('MUT-AWM-04: applyWeightMultiplier — Math.max clamp keeps weights ≥1 (boundary)', () => {
  it('multiplier 0 floor-clamps to 1 instead of zero', () => {
    const ir = makeWeightedIR();
    const out = applyWeightMultiplier(ir, 'WLD', [0, 1, 2], 0);
    const weighted = out.reels as Extract<typeof out.reels, { mode: 'weighted' }>;
    for (const reel of weighted.base) {
      // 1 × 0 = 0; clamp to 1.
      expect(reel['WLD']).toBe(1);
    }
  });

  it('tiny multiplier still produces ≥1 weight', () => {
    const ir = makeWeightedIR();
    const out = applyWeightMultiplier(ir, 'HP1', [0, 1, 2], 0.001);
    const weighted = out.reels as Extract<typeof out.reels, { mode: 'weighted' }>;
    for (const reel of weighted.base) {
      expect(reel['HP1']).toBeGreaterThanOrEqual(1);
    }
  });
});

// ─── analyzeSensitivity — defaults + arithmetic ────────────────────────────

describe('MUT-AS-01: analyzeSensitivity — non-weighted path returns empty deltas (line 60 ObjectLiteral)', () => {
  it('strips mode → deltas=[] and topInfluencers=[]', async () => {
    const ir: SlotGameIR = {
      ...makeWeightedIR(),
      reels: { mode: 'strips', base: [['LP1'], ['HP1'], ['WLD']] },
    };
    const report = await analyzeSensitivity(ir, { evalSpins: 1000 });
    expect(report.baseRtp).toBe(0);
    expect(report.baseHitRate).toBe(0);
    expect(report.deltas).toEqual([]);
    expect(report.topInfluencers).toEqual([]);
  });
});

describe('MUT-AS-02: analyzeSensitivity — opts.evalSpins default fallback (line 68 LogicalOperator)', () => {
  it('omitted evalSpins uses 10000 default and still returns finite numbers', async () => {
    const ir = makeWeightedIR();
    // We don't pass evalSpins — Stryker may mutate `opts?.evalSpins ?? 10000`
    // to `opts?.evalSpins && 10000`. The behaviour gap shows up because
    // `undefined && 10000 → undefined` would crash `runIRSimulation`.
    const report = await analyzeSensitivity(ir, { delta: 0.05 });
    expect(Number.isFinite(report.baseRtp)).toBe(true);
    expect(report.deltas.length).toBeGreaterThan(0);
  }, 60_000);
});

describe('MUT-AS-03: analyzeSensitivity — opts.delta default fallback (line 69 LogicalOperator)', () => {
  it('omitted delta uses 0.1 → sensitivity = rtpDelta / 0.1', async () => {
    const ir = makeWeightedIR();
    const reportA = await analyzeSensitivity(ir, { evalSpins: 1500 });
    const reportB = await analyzeSensitivity(ir, { evalSpins: 1500, delta: 0.1 });
    // Same default; identical seed→identical deltas.
    expect(reportA.deltas.length).toBe(reportB.deltas.length);
    for (let i = 0; i < reportA.deltas.length; i++) {
      expect(reportA.deltas[i]!.symbolId).toBe(reportB.deltas[i]!.symbolId);
      expect(reportA.deltas[i]!.delta).toBe(0.1);
    }
  }, 60_000);
});

describe('MUT-AS-04: analyzeSensitivity — perturbedResult deltas use SUBTRACTION not addition (line 93/94 ArithmeticOperator)', () => {
  it('rtpDelta is small (perturbed - base), not large (perturbed + base)', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 1500, delta: 0.1 });
    // After a +10% weight perturbation, an `rtpDelta = perturbed + base`
    // mutant would yield |rtpDelta| ≈ 2 × base_rtp ≈ 0.5–2.0; the correct
    // subtraction yields |rtpDelta| < 0.5 even on tiny synthetic fixtures.
    for (const d of report.deltas) {
      expect(Math.abs(d.rtpDelta)).toBeLessThan(0.5);
      expect(Math.abs(d.hitRateDelta)).toBeLessThan(0.5);
    }
  }, 60_000);
});

describe('MUT-AS-05: analyzeSensitivity — sensitivity uses DIVISION not multiplication (line 95 ArithmeticOperator)', () => {
  it('sensitivity ≈ rtpDelta / delta, not rtpDelta × delta', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 1500, delta: 0.1 });
    for (const d of report.deltas) {
      if (d.delta === 0) continue;
      // Correct: sensitivity = rtpDelta / delta = rtpDelta × 10 for delta=0.1.
      // Mutant: rtpDelta × delta = rtpDelta × 0.1.
      // Spread is 100× — easy assertion gap.
      const expected = d.rtpDelta / d.delta;
      expect(d.sensitivity).toBeCloseTo(expected, 8);
    }
  }, 60_000);
});

describe('MUT-AS-06: analyzeSensitivity — sensitivity zero-guard returns 0 not NaN (line 95 ConditionalExpression)', () => {
  it('delta=0 means sensitivity=0 (no division-by-zero NaN)', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 1500, delta: 0 });
    for (const d of report.deltas) {
      expect(d.delta).toBe(0);
      expect(d.sensitivity).toBe(0);
      // `Number.isNaN(0)` is false; this assertion catches a flipped
      // conditional that would let NaN through.
      expect(Number.isNaN(d.sensitivity)).toBe(false);
    }
  }, 60_000);
});

describe('MUT-AS-07: analyzeSensitivity — topInfluencers sorted DESCENDING by |sensitivity| (line 110 ArithmeticOperator)', () => {
  it('first influencer has the largest |sensitivity|', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 1500, delta: 0.1 });
    if (report.topInfluencers.length < 2) return;
    for (let i = 1; i < report.topInfluencers.length; i++) {
      const prev = Math.abs(report.topInfluencers[i - 1]!.sensitivity);
      const cur = Math.abs(report.topInfluencers[i]!.sensitivity);
      expect(prev).toBeGreaterThanOrEqual(cur);
    }
  }, 60_000);
});

describe('MUT-AS-08: analyzeSensitivity — topInfluencers capped at 5 (slice 0,5)', () => {
  it('length ≤ 5', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 1500, delta: 0.1 });
    expect(report.topInfluencers.length).toBeLessThanOrEqual(5);
  }, 60_000);
});

// ─── solveTargetRtp — convergence + boundary ───────────────────────────────

describe('MUT-STR-01: solveTargetRtp — non-weighted returns weightChange=1 (line 138 ObjectLiteral)', () => {
  it('strips IR → converged=false, weightChange=1', async () => {
    const ir: SlotGameIR = {
      ...makeWeightedIR(),
      reels: { mode: 'strips', base: [['LP1'], ['HP1'], ['WLD']] },
    };
    const out = await solveTargetRtp(ir, { targetRtp: 0.96, varySymbol: 'LP1' });
    expect(out.converged).toBe(false);
    expect(out.weightChange).toBe(1);
    expect(out.iterations).toBe(0);
    expect(out.achievedRtp).toBe(0);
  });
});

describe('MUT-STR-02: solveTargetRtp — config.tolerance default 0.001 (line 131 LogicalOperator)', () => {
  it('omitted tolerance uses 0.001 (assertion: a clearly-not-found target stays non-converged)', async () => {
    const ir = makeWeightedIR();
    // Target way outside reachable RTP for this fixture → no convergence.
    const out = await solveTargetRtp(ir, {
      targetRtp: 0.001,
      varySymbol: 'LP1',
      maxIterations: 10,
      evalSpins: 1000,
    });
    // The error must be > the (default 0.001) tolerance when no convergence.
    expect(out.error).toBeGreaterThan(0.001);
    // If `tolerance` defaulted to something larger (e.g. 1.0 due to a
    // mutant), `converged` would always trip true.
    expect(out.converged).toBe(false);
  }, 60_000);
});

describe('MUT-STR-03: solveTargetRtp — bisection uses MIDPOINT (line 163 ArithmeticOperator)', () => {
  it('with a wide bracket and few iterations, midpoint heuristic narrows the search', async () => {
    const ir = makeWeightedIR();
    const out = await solveTargetRtp(ir, {
      targetRtp: 0.92,
      varySymbol: 'HP1',
      maxIterations: 5,
      evalSpins: 1500,
    });
    // weightChange ∈ [0.1, 10] — must stay inside the bracket the
    // algorithm enforces. If `+` becomes `-` (line 163 mutation),
    // weightChange could go negative.
    expect(out.weightChange).toBeGreaterThanOrEqual(0.1);
    expect(out.weightChange).toBeLessThanOrEqual(10.0);
  }, 60_000);
});

describe('MUT-STR-04: solveTargetRtp — error uses Math.abs (boundary)', () => {
  it('error is always ≥ 0', async () => {
    const ir = makeWeightedIR();
    const out = await solveTargetRtp(ir, {
      targetRtp: 1.5, // unreachable; achievedRtp < targetRtp → diff < 0 raw
      varySymbol: 'HP1',
      maxIterations: 5,
      evalSpins: 1000,
    });
    expect(out.error).toBeGreaterThanOrEqual(0);
  }, 60_000);
});

describe('MUT-STR-05: solveTargetRtp — converged path uses strict `error < tolerance` (line 171 EqualityOperator)', () => {
  it('when error is exactly at tolerance boundary, branch fires correctly', async () => {
    // We can't control achievedRtp precisely enough to force `error ===
    // tolerance` — but we CAN force it BELOW tolerance by giving a huge
    // tolerance, and observe converged=true.
    const ir = makeWeightedIR();
    const out = await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'HP1',
      maxIterations: 30,
      evalSpins: 1500,
      tolerance: 100.0, // basically "anything is close enough"
    });
    expect(out.converged).toBe(true);
    expect(out.error).toBeLessThan(100.0);
  }, 60_000);
});

describe('MUT-STR-06: solveTargetRtp — bracket update direction (line 177 ConditionalExpression)', () => {
  it('if achievedRtp < target, lo bound moves up (search higher weights)', async () => {
    // The branch under test is:
    //   if (achievedRtp < config.targetRtp) lo = mid; else hi = mid;
    // A mutant flipping the comparison or the assignment would either
    // never converge or converge to the wrong direction. We force a
    // reachable RTP target and check the solver converges quickly.
    const ir = makeWeightedIR();
    const out = await solveTargetRtp(ir, {
      targetRtp: 0.93,
      varySymbol: 'HP1',
      maxIterations: 30,
      tolerance: 0.05, // relaxed for tiny fixture noise
      evalSpins: 1500,
    });
    expect(out.iterations).toBeLessThanOrEqual(30);
    // Must terminate; weightChange in bracket.
    expect(out.weightChange).toBeGreaterThan(0.1);
    expect(out.weightChange).toBeLessThan(10.0);
  }, 60_000);
});

