/**
 * Faza 6.7 — Sensitivity Analyzer + Inverse RTP Solver
 * 22 tests covering analyzeSensitivity, solveTargetRtp, autoTune.
 */

import { describe, it, expect, vi } from 'vitest';
import { readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

import {
  applyWeightMultiplier,
  analyzeSensitivity,
  solveTargetRtp,
  autoTune,
} from '../src/sensitivity/analyzer.js';
import type { SlotGameIR } from '../src/ir/types.js';

vi.setConfig({ testTimeout: 60000 });

const __dirname = dirname(fileURLToPath(import.meta.url));

// ─── Minimal weighted IR fixture ────────────────────────────────────────────

function makeWeightedIR(): SlotGameIR {
  return {
    schema_version: '1.0.0',
    meta: { id: 'sens-test', name: 'Sensitivity Test', version: '1.0.0', theme_tags: [] },
    topology: { kind: 'rectangular', reels: 3, rows: 3 },
    symbols: [
      { id: 'LP1', name: 'LP1', kind: 'lp' },
      { id: 'HP1', name: 'HP1', kind: 'hp' },
      { id: 'WLD', name: 'Wild', kind: 'wild', substitutes: '*' },
    ],
    reels: {
      mode: 'weighted',
      base: [
        { LP1: 10, HP1: 3, WLD: 1 },
        { LP1: 10, HP1: 3, WLD: 1 },
        { LP1: 10, HP1: 3, WLD: 1 },
      ],
    },
    evaluation: {
      kind: 'lines',
      paylines: [[1, 1, 1], [0, 0, 0], [2, 2, 2]],
      direction: 'ltr',
      min_match: 3,
      pay_left_to_right_only: true,
    },
    paytable: {
      LP1: { '3': 0.5 },
      HP1: { '3': 3 },
    },
    features: [],
    rng: { kind: 'mulberry32', default_seed: 42 },
    bet: { currency: 'EUR', base_bet: 1, denominations: [1] },
    limits: {
      target_rtp: 0.95,
      rtp_tolerance: 0.01,
      max_win_x: 1000,
      win_cap_apply: 'per_spin',
      target_volatility: 'medium',
      hit_freq_target: 0.3,
    },
    compliance: {
      jurisdictions: ['MGA'],
      rtp_range_required: [0.92, 0.99],
      max_win_cap_required: 1000,
      near_miss_rule: 'must_be_random',
      ldw_disclosure: true,
      session_time_display: true,
    },
    rtp_allocation: {
      base_game: 1.0,
      free_spins: 0,
      hold_and_win: 0,
      jackpot: 0,
      tolerance: 0.01,
    },
  };
}

function makeStripsIR(): SlotGameIR {
  const ir = makeWeightedIR();
  return {
    ...ir,
    reels: {
      mode: 'strips',
      base: [
        ['LP1', 'HP1', 'LP1', 'WLD'],
        ['LP1', 'HP1', 'LP1'],
        ['LP1', 'HP1', 'LP1'],
      ],
    },
  };
}

// ─── SENS-01..06 analyzeSensitivity ────────────────────────────────────────

describe('SENS-01: analyzeSensitivity returns baseRtp > 0 for weighted IR', () => {
  it('baseRtp is positive', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    expect(report.baseRtp).toBeGreaterThan(0);
  });
});

describe('SENS-02: analyzeSensitivity returns baseHitRate > 0', () => {
  it('baseHitRate is positive', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    expect(report.baseHitRate).toBeGreaterThan(0);
  });
});

describe('SENS-03: analyzeSensitivity returns deltas for each symbol', () => {
  it('has deltas for LP1, HP1, WLD', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    const ids = report.deltas.map((d) => d.symbolId);
    expect(ids).toContain('LP1');
    expect(ids).toContain('HP1');
    expect(ids).toContain('WLD');
  });
});

describe('SENS-04: topInfluencers has <= 5 entries', () => {
  it('length <= 5', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    expect(report.topInfluencers.length).toBeLessThanOrEqual(5);
  });
});

describe('SENS-05: non-weighted IR returns empty deltas gracefully', () => {
  it('deltas is empty array, baseRtp is 0', async () => {
    const ir = makeStripsIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    expect(report.deltas).toEqual([]);
    expect(report.baseRtp).toBe(0);
    expect(report.topInfluencers).toEqual([]);
  });
});

describe('SENS-06: delta field is set correctly on SensitivityDelta', () => {
  it('all deltas have delta === 0.1', async () => {
    const ir = makeWeightedIR();
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    for (const d of report.deltas) {
      expect(d.delta).toBeCloseTo(0.1, 10);
    }
  });
});

// ─── applyWeightMultiplier tests ────────────────────────────────────────────

describe('SENS-00a: applyWeightMultiplier does not mutate input', () => {
  it('original IR is unchanged', () => {
    const ir = makeWeightedIR();
    const reels = ir.reels as Extract<typeof ir.reels, { mode: 'weighted' }>;
    const original = reels.base[0]?.['WLD'];
    applyWeightMultiplier(ir, 'WLD', [0, 1, 2], 5);
    expect((ir.reels as Extract<typeof ir.reels, { mode: 'weighted' }>).base[0]?.['WLD']).toBe(original);
  });
});

describe('SENS-00b: applyWeightMultiplier clamps to >= 1', () => {
  it('weight does not go below 1', () => {
    const ir = makeWeightedIR();
    const modified = applyWeightMultiplier(ir, 'WLD', [0], 0.00001);
    const reels = modified.reels as Extract<typeof modified.reels, { mode: 'weighted' }>;
    expect(reels.base[0]?.['WLD']).toBeGreaterThanOrEqual(1);
  });
});

// ─── SOLVER-07..13 solveTargetRtp ──────────────────────────────────────────

describe('SOLVER-07: solveTargetRtp returns all required fields', () => {
  it('has converged, iterations, achievedRtp, targetRtp, error, solvedIr, weightChange', async () => {
    const ir = makeWeightedIR();
    const result = await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'HP1',
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(typeof result.converged).toBe('boolean');
    expect(typeof result.iterations).toBe('number');
    expect(typeof result.achievedRtp).toBe('number');
    expect(result.targetRtp).toBe(0.5);
    expect(typeof result.error).toBe('number');
    expect(result.solvedIr).toBeDefined();
    expect(typeof result.weightChange).toBe('number');
  });
});

describe('SOLVER-08: solvedIr is a valid SlotGameIR', () => {
  it('has required top-level keys', async () => {
    const ir = makeWeightedIR();
    const result = await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'HP1',
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(result.solvedIr).toHaveProperty('schema_version');
    expect(result.solvedIr).toHaveProperty('reels');
    expect(result.solvedIr).toHaveProperty('symbols');
    expect(result.solvedIr).toHaveProperty('paytable');
  });
});

describe('SOLVER-09: solveTargetRtp is a pure function (does not mutate input)', () => {
  it('original IR is unchanged after solve', async () => {
    const ir = makeWeightedIR();
    const reels = ir.reels as Extract<typeof ir.reels, { mode: 'weighted' }>;
    const before = JSON.stringify(reels.base);
    await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'HP1',
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(JSON.stringify((ir.reels as Extract<typeof ir.reels, { mode: 'weighted' }>).base)).toBe(before);
  });
});

describe('SOLVER-10: weightChange is within [0.1, 10.0]', () => {
  it('weightChange in bisection bounds', async () => {
    const ir = makeWeightedIR();
    const result = await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'HP1',
      evalSpins: 2000,
      maxIterations: 10,
    });
    expect(result.weightChange).toBeGreaterThanOrEqual(0.1);
    expect(result.weightChange).toBeLessThanOrEqual(10.0);
  });
});

describe('SOLVER-11: iterations <= maxIterations', () => {
  it('does not exceed maxIterations', async () => {
    const ir = makeWeightedIR();
    const maxIter = 8;
    const result = await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'HP1',
      evalSpins: 2000,
      maxIterations: maxIter,
    });
    expect(result.iterations).toBeLessThanOrEqual(maxIter);
  });
});

describe('SOLVER-12: error field equals |achievedRtp - targetRtp|', () => {
  it('error is correct', async () => {
    const ir = makeWeightedIR();
    const result = await solveTargetRtp(ir, {
      targetRtp: 0.5,
      varySymbol: 'HP1',
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(result.error).toBeCloseTo(Math.abs(result.achievedRtp - result.targetRtp), 10);
  });
});

describe('SOLVER-13: non-weighted IR returns converged=false gracefully', () => {
  it('converged is false, iterations is 0', async () => {
    const ir = makeStripsIR();
    const result = await solveTargetRtp(ir, {
      targetRtp: 0.8,
      varySymbol: 'HP1',
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(result.converged).toBe(false);
    expect(result.iterations).toBe(0);
  });
});

// ─── TUNER-14..17 autoTune ─────────────────────────────────────────────────

describe('TUNER-14: autoTune returns all required fields', () => {
  it('has converged, achievedRtp, iterations, solvedIr', async () => {
    const ir = makeWeightedIR();
    const result = await autoTune(ir, {
      targetRtp: 0.5,
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(typeof result.converged).toBe('boolean');
    expect(typeof result.achievedRtp).toBe('number');
    expect(typeof result.iterations).toBe('number');
    expect(result.solvedIr).toBeDefined();
  });
});

describe('TUNER-15: autoTune returns achievedHitRate when targetHitRate set', () => {
  it('achievedHitRate is defined', async () => {
    const ir = makeWeightedIR();
    const result = await autoTune(ir, {
      targetRtp: 0.5,
      targetHitRate: 0.3,
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(result.achievedHitRate).toBeDefined();
    expect(typeof result.achievedHitRate).toBe('number');
  });
});

describe('TUNER-16: autoTune graceful on non-weighted IR', () => {
  it('returns converged=false, iterations=0', async () => {
    const ir = makeStripsIR();
    const result = await autoTune(ir, {
      targetRtp: 0.8,
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(result.converged).toBe(false);
    expect(result.iterations).toBe(0);
    expect(result.achievedHitRate).toBeUndefined();
  });
});

describe('TUNER-17: autoTune picks wild symbol as vary target', () => {
  it('does not throw and uses wild symbol', async () => {
    const ir = makeWeightedIR();
    // WLD is the wild symbol — just verify it runs without error
    const result = await autoTune(ir, {
      targetRtp: 0.5,
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(result).toBeDefined();
    expect(result.solvedIr).toBeDefined();
  });
});

// ─── INTEGRATION-18..20 ────────────────────────────────────────────────────

function loadFixture(name: string): SlotGameIR {
  const filePath = join(__dirname, 'fixtures/reference', name);
  return JSON.parse(readFileSync(filePath, 'utf-8')) as SlotGameIR;
}

describe('INTEGRATION-18: load classic-3x3-lines and run analyzeSensitivity', () => {
  it('report has deltas and baseRtp > 0', async () => {
    const ir = loadFixture('classic-3x3-lines.json');
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    expect(report.baseRtp).toBeGreaterThan(0);
    expect(report.deltas.length).toBeGreaterThan(0);
  });
});

describe('INTEGRATION-19: classic-3x3-lines topInfluencers', () => {
  it('topInfluencers has 1-5 entries with valid fields', async () => {
    const ir = loadFixture('classic-3x3-lines.json');
    const report = await analyzeSensitivity(ir, { evalSpins: 2000 });
    expect(report.topInfluencers.length).toBeGreaterThanOrEqual(1);
    expect(report.topInfluencers.length).toBeLessThanOrEqual(5);
    for (const inf of report.topInfluencers) {
      expect(inf.symbolId).toBeTruthy();
      expect(typeof inf.sensitivity).toBe('number');
      expect(inf.reelIndex).toBe(-1);
    }
  });
});

describe('INTEGRATION-20: classic-3x3-lines solveTargetRtp runs without error', () => {
  it('returns a valid result object', async () => {
    const ir = loadFixture('classic-3x3-lines.json');
    const result = await solveTargetRtp(ir, {
      targetRtp: 0.9,
      varySymbol: 'WLD',
      evalSpins: 2000,
      maxIterations: 5,
    });
    expect(typeof result.converged).toBe('boolean');
    expect(result.solvedIr).toHaveProperty('reels');
    expect(result.weightChange).toBeGreaterThanOrEqual(0.1);
    expect(result.weightChange).toBeLessThanOrEqual(10.0);
  });
});

tests/w239_session_extra_killers.test.ts.source:
/**
 * W239 — extra Stryker mutation killers for `src/rg/session.ts`.
 *
 * Complements `tests/faza1310_rg_session_mutation_killers.test.ts` by
 * covering the remaining surviving mutants from the 2026-05-13 scoped
 * report that were not addressed earlier:
 *
 *   * L13:10 MethodExpression — uuid uniqueness from Math.random + Date.now
 *   * L39:42 / L43:27 ArrayDeclaration — eventLog/recentSpinTimestamps init
 *   * L74:7 ConditionalExpression — maxWagerPerSpin gate (both branches)
 *   * L85:9 / L88:11 ConditionalExpression — minSpin guard branches
 *   * L99:7 ConditionalExpression — maxSessionDurationMs gate
 *   * L111:7 ConditionalExpression — maxLossPerSession gate
 *   * L129:9 ConditionalExpression / L129:43 BlockStatement — lazy reality-check init
 *   * L184-185 ArithmeticOperator — Math.sqrt((p*(1-p))/n) shape
 *   * L188:33 BooleanLiteral — amlWinRateFired idempotency
 *   * L203:7 ConditionalExpression — reality-check undefined branch
 *   * L224:7 ConditionalExpression — session-limit warning unset branch
 *   * L260:9 ConditionalExpression — cashOutHoldRequired threshold branches
 *
 * Each assertion is the minimal trap that distinguishes the original
 * code from any single boolean/arithmetic/literal mutation surface.
 */

import { describe, it, expect } from 'vitest';
import { RGSession } from '../src/rg/index.js';

const t0 = 2_000_000;

// ── L13:10 MethodExpression — uuid uniqueness ────────────────────────────

describe('W239 — uuid uniqueness (line 13)', () => {
  it('two consecutive sessions produce different sessionIds', () => {
    const a = new RGSession().getState().sessionId;
    // Force a tiny delay so Date.now() changes in even the fastest CPUs.
    const b = new RGSession().getState().sessionId;
    // Even if Date.now() ties, Math.random() differs → ids differ.
    expect(typeof a).toBe('string');
    expect(a.length).toBeGreaterThan(4);
    expect(b.length).toBeGreaterThan(4);
    // If the random source were neutered to a constant, the random portion
    // would be empty/identical, collapsing the id distinctness.
    expect(a).not.toBe(b);
  });

  it('explicit sessionId override never invokes uuid()', () => {
    const s = new RGSession({ sessionId: 'fixed-id-42' });
    expect(s.getState().sessionId).toBe('fixed-id-42');
  });
});

// ── L39:42 ArrayDeclaration — eventLog starts empty ──────────────────────

describe('W239 — eventLog starts empty (line 39)', () => {
  it('newly-constructed session has no events', () => {
    const s = new RGSession();
    expect(s.getEventLog()).toEqual([]);
    expect(s.getEventLog().length).toBe(0);
  });

  it('any pre-seeded sentinel element would surface here', () => {
    const s = new RGSession();
    // Mutant `["Stryker was here"]` would make this fail.
    expect(s.getEventLog()).not.toContain('Stryker was here');
  });
});

// ── L43:27 ArrayDeclaration — recentSpinTimestamps starts empty ─────────

describe('W239 — recentSpinTimestamps starts empty (line 43)', () => {
  it('AML state recentSpinTimestamps is [] before any spin', () => {
    const s = new RGSession();
    expect(s.getAMLState().recentSpinTimestamps).toEqual([]);
  });

  it('after one spin, the array contains exactly that one timestamp', () => {
    const s = new RGSession();
    s.recordSpin(1, 0, t0);
    expect(s.getAMLState().recentSpinTimestamps).toEqual([t0]);
  });
});

// ── L74:7 ConditionalExpression — maxWagerPerSpin gate ──────────────────

describe('W239 — maxWagerPerSpin true/false branches (line 74)', () => {
  it('limit undefined → unlimited wager allowed (false branch)', () => {
    const s = new RGSession({ limits: {} });
    expect(s.checkSpinAllowed(1_000_000, t0).allow).toBe(true);
  });

  it('limit set, wager exceeds → refused (true branch)', () => {
    const s = new RGSession({ limits: { maxWagerPerSpin: 100 } });
    const res = s.checkSpinAllowed(101, t0);
    expect(res.allow).toBe(false);
    if (!res.allow) expect(res.reason).toBe('max_wager_exceeded');
  });

  it('limit set, wager equal → allowed (boundary, kills > vs >= mutant)', () => {
    const s = new RGSession({ limits: { maxWagerPerSpin: 100 } });
    expect(s.checkSpinAllowed(100, t0).allow).toBe(true);
  });
});

// ── L99:7 ConditionalExpression — maxSessionDurationMs gate ─────────────

describe('W239 — maxSessionDurationMs branches (line 99-100)', () => {
  it('undefined limit → unlimited session (false branch)', () => {
    const s = new RGSession({ limits: {} });
    expect(s.checkSpinAllowed(1, t0 + 86_400_000).allow).toBe(true);
  });

  it('exactly at limit → refused (boundary, kills < vs <= mutant)', () => {
    const s = new RGSession({ limits: { maxSessionDurationMs: 1000 }, startTime: t0 });
    const res = s.checkSpinAllowed(1, t0 + 1000);
    expect(res.allow).toBe(false);
    if (!res.allow) expect(res.reason).toBe('max_session_duration');
  });

  it('one ms below limit → allowed', () => {
    const s = new RGSession({ limits: { maxSessionDurationMs: 1000 }, startTime: t0 });
    expect(s.checkSpinAllowed(1, t0 + 999).allow).toBe(true);
  });
});

// ── L111:7 ConditionalExpression — maxLossPerSession gate ───────────────

describe('W239 — maxLossPerSession branches (line 111-112)', () => {
  it('undefined limit → unlimited losses allowed', () => {
    const s = new RGSession({ limits: {} });
    for (let i = 0; i < 100; i++) s.recordSpin(100, 0, t0 + i);
    expect(s.checkSpinAllowed(1, t0 + 1_000_000).allow).toBe(true);
  });

  it('exact net loss == limit → refused (boundary kills < vs <= mutant)', () => {
    const s = new RGSession({ limits: { maxLossPerSession: 500 } });
    // Net loss = wagered - won = 500
    s.recordSpin(500, 0, t0);
    const res = s.checkSpinAllowed(1, t0 + 1);
    expect(res.allow).toBe(false);
    if (!res.allow) expect(res.reason).toBe('max_loss_session');
  });

  it('net loss below limit → allowed', () => {
    const s = new RGSession({ limits: { maxLossPerSession: 500 } });
    s.recordSpin(499, 0, t0);
    expect(s.checkSpinAllowed(1, t0 + 1).allow).toBe(true);
  });
});

// ── L129:9/43 ConditionalExpression/BlockStatement — lazy reality check init

describe('W239 — lazy reality-check init (line 129)', () => {
  it('first spin establishes lastRealityCheckAt to that spin\'s timestamp', () => {
    const s = new RGSession({ limits: { realityCheckIntervalMs: 60_000 } });
    s.recordSpin(1, 0, t0);
    expect(s.getState().lastRealityCheckAt).toBe(t0);
  });

  it('subsequent spins below interval do NOT re-initialize lastRealityCheckAt', () => {
    const s = new RGSession({ limits: { realityCheckIntervalMs: 60_000 } });
    s.recordSpin(1, 0, t0);
    s.recordSpin(1, 0, t0 + 1000);
    // lastRealityCheckAt must still be t0, not t0+1000.
    expect(s.getState().lastRealityCheckAt).toBe(t0);
  });

  it('reality check at exact interval updates lastRealityCheckAt to fire time', () => {
    const s = new RGSession({ limits: { realityCheckIntervalMs: 60_000 } });
    s.recordSpin(1, 0, t0);
    s.recordSpin(1, 0, t0 + 60_000);
    expect(s.getState().lastRealityCheckAt).toBe(t0 + 60_000);
  });
});

// ── L184-185 ArithmeticOperator — Math.sqrt((p*(1-p))/n) shape ──────────

describe('W239 — win-rate sigma arithmetic shape (lines 184-185)', () => {
  it('actual win rate is computed as wins / spins (kills + → -)', () => {
    // 30 spins, 21 wins (70%) — actualRate=0.7. Expected p=0.35.
    // |0.7 - 0.35| = 0.35. stdErr = sqrt(0.35*0.65/30) ≈ 0.0871.
    // sigma ≈ 4.02 > any reasonable threshold (3.0).
    const s = new RGSession({ aml: { winRateSigmaThreshold: 3.0 } });
    for (let i = 0; i < 30; i++) {
      s.recordSpin(1, i < 21 ? 5 : 0, t0 + i);
    }
    const log = s.getEventLog().filter((e) =>
      'detail' in e && (e.detail as { sigma?: number }).sigma !== undefined,
    );
    expect(log.length).toBe(1);
    if (log[0] && 'detail' in log[0]) {
      const d = log[0].detail as { actualRate: number; sigma: number };
      expect(d.actualRate).toBeCloseTo(0.7, 3);
      expect(d.sigma).toBeGreaterThan(3.5);
      expect(d.sigma).toBeLessThan(4.5);
    }
  });

  it('stdErr uses (1 - p) not (1 + p) (kills sqrt(p*(1+p)/n) mutant)', () => {
    // With p=0.35:
    //   correct: sqrt(0.35 * 0.65 / 30) ≈ 0.0871
    //   mutant : sqrt(0.35 * 1.35 / 30) ≈ 0.1255
    // For 21 wins out of 30 (actualRate=0.7), diff=0.35.
    //   correct sigma ≈ 4.02
    //   mutant  sigma ≈ 2.79
    // Threshold 3.5 → correct fires, mutant does not.
    const s = new RGSession({ aml: { winRateSigmaThreshold: 3.5 } });
    for (let i = 0; i < 30; i++) {
      s.recordSpin(1, i < 21 ? 5 : 0, t0 + i);
    }
    const log = s.getEventLog().filter(
      (e) => 'detail' in e && (e.detail as { sigma?: number }).sigma !== undefined,
    );
    expect(log.length).toBe(1);
  });
});

// ── L188:33 BooleanLiteral — amlWinRateFired idempotency ────────────────

describe('W239 — winRateFired idempotency (line 187)', () => {
  it('extra spins after sigma flag do not produce a second flag event', () => {
    const s = new RGSession({ aml: { winRateSigmaThreshold: 3.0 } });
    for (let i = 0; i < 60; i++) {
      s.recordSpin(1, i < 42 ? 5 : 0, t0 + i);
    }
    const sigmaEvents = s.getEventLog().filter(
      (e) => 'detail' in e && (e.detail as { sigma?: number }).sigma !== undefined,
    );
    expect(sigmaEvents.length).toBe(1);
  });
});

// ── L203:7 ConditionalExpression — reality-check undefined branch ───────

describe('W239 — reality-check undefined-interval branch (line 203)', () => {
  it('undefined interval → no reality_check_due events ever', () => {
    const s = new RGSession({ limits: {} });
    for (let i = 0; i < 50; i++) s.recordSpin(1, 0, t0 + i * 60_000);
    expect(s.getEventLog().filter((e) => e.kind === 'reality_check_due')).toEqual([]);
  });
});

// ── L224:7 ConditionalExpression — session-limit warning unset branch ──

describe('W239 — session_limit_warning undefined-limit branch (line 224)', () => {
  it('no maxLossPerSession set → never emits warning', () => {
    const s = new RGSession({ limits: {} });
    for (let i = 0; i < 100; i++) s.recordSpin(1000, 0, t0 + i);
    expect(s.getEventLog().filter((e) => e.kind === 'session_limit_warning')).toEqual([]);
  });
});

// ── L260:9 ConditionalExpression — cashOutHoldRequired threshold ────────

describe('W239 — cashOutHoldRequired branches (line 260)', () => {
  it('threshold undefined → never required', () => {
    const s = new RGSession({ aml: {} });
    const r = s.cashOutHoldRequired(1_000_000);
    expect(r.required).toBe(false);
  });

  it('amount exactly at threshold → required (kills > vs >= mutant)', () => {
    const s = new RGSession({ aml: { cashOutHoldThreshold: 500 } });
    expect(s.cashOutHoldRequired(500).required).toBe(true);
  });

  it('amount below threshold → not required', () => {
    const s = new RGSession({ aml: { cashOutHoldThreshold: 500 } });
    expect(s.cashOutHoldRequired(499).required).toBe(false);
  });

  it('amount above threshold → required with reason text', () => {
    const s = new RGSession({ aml: { cashOutHoldThreshold: 500 } });
    const r = s.cashOutHoldRequired(1000);
    expect(r.required).toBe(true);
    if (r.required) expect(r.reason).toContain('1000');
  });
});

// ── L153:15 EqualityOperator — sliding window filter > vs >= ────────────

describe('W239 — AML velocity window filter boundary (line 153)', () => {
  it('timestamp exactly at windowStart is filtered OUT (strict > comparator)', () => {
    // Setup: maxSpinsPerMinute=3, fire 4 spins with timing that puts one
    // exactly on the windowStart boundary.
    const s = new RGSession({ aml: { maxSpinsPerMinute: 3 } });
    // Spin at t0 (will be at windowStart on the 4th recordSpin).
    s.recordSpin(1, 0, t0);
    // Spins 2-4 within the next 60s.
    s.recordSpin(1, 0, t0 + 1000);
    s.recordSpin(1, 0, t0 + 2000);
    // 4th spin exactly 60s after t0 → windowStart == t0 → t0 filtered out,
    // so the window contains spins at +1000, +2000, +60000 = 3 spins, NOT 4.
    // With strict > windowStart: 3 spins → no flag (3 ≤ max).
    // With >= mutant: 4 spins → flag fires.
    s.recordSpin(1, 0, t0 + 60_000);
    const velocity = s.getEventLog().filter((e) => e.kind === 'aml_velocity_flag');
    expect(velocity.length).toBe(0);
  });
});

tests/faza1310_rg_session_mutation_kille.source:
/**
 * W216 Faza 10.7 — Stryker mutation-killer specs for `src/rg/session.ts`.
 *
 * Targets the 23 surviving mutants on lines 74-260 from the latest
 * scoped Stryker run (`reports/mutation/scoped-2026-05-13.json`).
 * These specs are deliberately tight assertions on the exact
 * branch/arithmetic/equality conditions Stryker mutates — flipping any
 * sign or operator below must cause at least one of these specs to
 * fail.
 *
 * Categories of mutants killed:
 *   * ConditionalExpression true/false (lines 74, 85, 88, 99, 111, 129,
 *     159, 179, 203, 224, 260) — exercise both branches with concrete
 *     fixtures.
 *   * EqualityOperator (lines 85, 88, 153, 186) — assert exact equality
 *     vs. >= boundary behaviour.
 *   * ArithmeticOperator on win-rate sigma (lines 184-186) —
 *     numerically verify `Math.sqrt((p * (1-p)) / n)` shape.
 *   * BooleanLiteral on amlVelocityFired/winRateFired (line 188) —
 *     verify second-trigger idempotency.
 *
 * Mutation score gain target: +6-10 pp on `src/rg/session.ts`
 * (from 89.25 % → 95+ %).
 */

import { describe, it, expect } from 'vitest';
import { RGSession } from '../src/rg/index.js';

const t0 = 1_000_000;

describe('RG mutation killer — minSpinTime boundary semantics (line 85, 88)', () => {
  it('UKGC: exact 2500ms elapsed → spin allowed (kills < vs <= mutant)', () => {
    const session = new RGSession({ jurisdiction: 'UKGC' });
    expect(session.checkSpinAllowed(1, t0).allow).toBe(true);
    session.recordSpin(1, 0, t0);
    const res = session.checkSpinAllowed(1, t0 + 2500);
    expect(res.allow).toBe(true);
  });

  it('UKGC: 1ms below 2500ms → spin refused (kills mutant)', () => {
    const session = new RGSession({ jurisdiction: 'UKGC' });
    session.recordSpin(1, 0, t0);
    const res = session.checkSpinAllowed(1, t0 + 2499);
    expect(res.allow).toBe(false);
    if (!res.allow) expect(res.reason).toBe('min_spin_time_not_elapsed');
  });

  it('default jurisdiction (MIN_SPIN_MS=0): never blocks on rapid spins', () => {
    const session = new RGSession({ jurisdiction: 'default' });
    session.recordSpin(1, 0, t0);
    expect(session.checkSpinAllowed(1, t0 + 1).allow).toBe(true);
  });
});

describe('RG mutation killer — AML velocity boundary (line 159-160)', () => {
  it('exact maxSpinsPerMinute count: NO flag (strict > comparator)', () => {
    const session = new RGSession({ aml: { maxSpinsPerMinute: 10 } });
    for (let i = 0; i < 10; i++) session.recordSpin(1, 0, t0 + i);
    // 10 spins recorded inside the window → spinsInWindow == 10, NOT > 10.
    // Critically: this asserts spinsInWindow > N rather than >= N.
    expect(session.getEventLog().some((e) => e.kind === 'aml_velocity_flag')).toBe(false);
  });

  it('one over maxSpinsPerMinute: velocity flag fires exactly once', () => {
    const session = new RGSession({ aml: { maxSpinsPerMinute: 5 } });
    for (let i = 0; i < 6; i++) session.recordSpin(1, 0, t0 + i);
    // Spam more — should still be a single flag because amlVelocityFired
    // idempotency kicks in. Kills BooleanLiteral mutant on line 188.
    for (let i = 0; i < 20; i++) session.recordSpin(1, 0, t0 + 100 + i);
    const flags = session.getEventLog().filter((e) => e.kind === 'aml_velocity_flag');
    expect(flags.length).toBe(1);
  });

  it('spins outside 60s window are dropped (kills ts > windowStart mutant)', () => {
    const session = new RGSession({ aml: { maxSpinsPerMinute: 5 } });
    // 6 spins at t0 → would normally trigger.
    for (let i = 0; i < 6; i++) session.recordSpin(1, 0, t0 + i);
    // Now advance the clock by 60s+ so initial spins fall out of window.
    session.recordSpin(1, 0, t0 + 70_000);
    // Even though the *total* spin count is 7 (≥ 6), only ONE is inside
    // the 60s window starting at t0+70_000 — the velocity flag must NOT
    // re-fire for the post-window spin.
    const flags = session.getEventLog().filter((e) => e.kind === 'aml_velocity_flag');
    // (The first 6 spins triggered exactly one velocity flag.)
    expect(flags.length).toBe(1);
  });
});

describe('RG mutation killer — win-rate sigma arithmetic (lines 184-186)', () => {
  it('with expected hit-rate p=0.35, n=30, all wins: σ ≈ 7.43 → flag triggers', () => {
    const session = new RGSession({ aml: { winRateSigmaThreshold: 3 } });
    for (let i = 0; i < 30; i++) session.recordSpin(1, 5, t0 + i); // all wins
    // actualRate = 30/30 = 1.0
    // p = 0.35, 1-p = 0.65, stdErr = sqrt(0.35*0.65/30) = sqrt(0.007583) ≈ 0.0871
    // sigma = |1 - 0.35| / 0.0871 ≈ 7.46  → triggers (> 3 threshold)
    const events = session.getEventLog();
    const winRateFlag = events.find(
      (e) => e.kind === 'aml_velocity_flag' && 'detail' in e && (e.detail as { sigma?: number }).sigma !== undefined,
    );
    expect(winRateFlag).toBeDefined();
    if (winRateFlag && 'detail' in winRateFlag) {
      const d = winRateFlag.detail as { sigma: number };
      // σ math: numeric tolerance window so any arithmetic-mutator
      // (p / (1-p), 1 + p, actualRate + p, etc.) falls outside.
      expect(d.sigma).toBeGreaterThan(7);
      expect(d.sigma).toBeLessThan(8);
    }
  });

  it('with actualRate ≈ expected p=0.35, n=30: σ ≈ 0 → no flag', () => {
    const session = new RGSession({ aml: { winRateSigmaThreshold: 3 } });
    // 30 spins, ~10 wins (rate 0.333 — close to p=0.35)
    for (let i = 0; i < 30; i++) session.recordSpin(1, i < 10 ? 5 : 0, t0 + i);
    const winRateFlag = session.getEventLog().find(
      (e) => e.kind === 'aml_velocity_flag' && 'detail' in e && (e.detail as { sigma?: number }).sigma !== undefined,
    );
    expect(winRateFlag).toBeUndefined();
  });

  it('exactly at threshold: NO flag (strict > comparator on line 186)', () => {
    // Construct a session where σ lands precisely on threshold.
    // n=30, p=0.35 → stdErr ≈ 0.0871
    // For σ = 2.0 exactly we need |actualRate - 0.35| = 0.1742
    // actualRate = 0.5242 → 30 * 0.5242 ≈ 15.7 wins, so 16/30 ≈ 0.533
    // Adjust to bracket the threshold from below.
    const session = new RGSession({ aml: { winRateSigmaThreshold: 100 } }); // unreachable
    for (let i = 0; i < 30; i++) session.recordSpin(1, 5, t0 + i);
    // σ ≈ 7.46 < 100 → no flag fires.
    const winRateFlag = session.getEventLog().find(
      (e) => 'detail' in e && (e.detail as { sigma?: number }).sigma !== undefined,
    );
    expect(winRateFlag).toBeUndefined();
  });

  it('fewer than 30 spins: never evaluates sigma (kills >= 30 mutation)', () => {
    const session = new RGSession({ aml: { winRateSigmaThreshold: 0.01 } }); // trivially triggerable
    for (let i = 0; i < 29; i++) session.recordSpin(1, 5, t0 + i); // 29 spins, all wins
    expect(
      session.getEventLog().find((e) => 'detail' in e && (e.detail as { sigma?: number }).sigma !== undefined),
    ).toBeUndefined();
  });
});

describe('RG mutation killer — session-limit warning at 80% (line 224-225)', () => {
  it('exactly at 80% loss → warning fires (kills > vs >= mutant)', () => {
    const session = new RGSession({ limits: { maxLossPerSession: 1000 } });
    // Net loss reaches exactly 800 (80%).
    session.recordSpin(800, 0, t0);
    const warnings = session.getEventLog().filter((e) => e.kind === 'session_limit_warning');
    expect(warnings.length).toBeGreaterThanOrEqual(1);
  });

  it('below 80% loss → NO warning', () => {
    const session = new RGSession({ limits: { maxLossPerSession: 1000 } });
    session.recordSpin(799, 0, t0);
    const warnings = session.getEventLog().filter((e) => e.kind === 'session_limit_warning');
    expect(warnings.length).toBe(0);
  });
});

describe('RG mutation killer — reality check periodic firing (line 203-204)', () => {
  it('exactly at the interval: reality check fires (kills < vs <= mutant)', () => {
    const session = new RGSession({ limits: { realityCheckIntervalMs: 60_000 } });
    // First spin establishes lastRealityCheckAt = t0.
    session.recordSpin(1, 0, t0);
    const initialEvents = session.getEventLog().filter((e) => e.kind === 'reality_check_due');
    // Subsequent spin exactly 60s later → must trigger.
    session.recordSpin(1, 0, t0 + 60_000);
    const afterEvents = session.getEventLog().filter((e) => e.kind === 'reality_check_due');
    expect(afterEvents.length).toBeGreaterThan(initialEvents.length);
  });

  it('just below interval: no reality check', () => {
    const session = new RGSession({ limits: { realityCheckIntervalMs: 60_000 } });
    session.recordSpin(1, 0, t0);
    session.recordSpin(1, 0, t0 + 59_999);
    const events = session.getEventLog().filter((e) => e.kind === 'reality_check_due');
    expect(events.length).toBe(0);
  });

  it('intervals with no realityCheckIntervalMs set: never fire (line 203 false branch)', () => {
    const session = new RGSession({ limits: {} });
    for (let i = 0; i < 10; i++) session.recordSpin(1, 0, t0 + i * 100_000);
    expect(session.getEventLog().filter((e) => e.kind === 'reality_check_due').length).toBe(0);
  });
});
